import { Component, OnInit } from '@angular/core';
import { Todo, TodoService } from './todo.service';

@Component({
  selector: 'app-root',
  templateUrl: './app.component.html',
  styleUrls: ['./app.component.css']
})
export class AppComponent implements OnInit {
  todos: Todo[] = [];
  title = '';           
  editingId: number | null = null; 

  constructor(private todoService: TodoService) {}

  ngOnInit() {
    this.loadTodos();
  }

  loadTodos() {
    this.todoService.getAll().subscribe(data => {
      this.todos = data;
    });
  }

  // ใช้เพิ่มใหม่ และบันทึกการแก้ไข
  save() {
    if (!this.title.trim()) return;

    if (this.editingId === null) {
      // (Create)
      const newTodo = { id: 0, title: this.title, isCompleted: false };
      this.todoService.create(newTodo).subscribe(() => {
        this.title = '';
        this.loadTodos();
      });
    } else {
      //  (Update)
      const updated = { id: this.editingId, title: this.title, isCompleted: false };
      this.todoService.update(this.editingId, updated).subscribe(() => {
        this.title = '';
        this.editingId = null;
        this.loadTodos();
      });
    }
  }

  edit(todo: Todo) {
    this.editingId = todo.id;
    this.title = todo.title;
  }

  cancelEdit() {
    this.editingId = null;
    this.title = '';
  }

  toggleCompleted(todo: Todo) {
    const updated = { ...todo, isCompleted: !todo.isCompleted };
    this.todoService.update(todo.id, updated).subscribe(() => {
      this.loadTodos();
    });
  }

  delete(id: number) {
    this.todoService.delete(id).subscribe(() => {
      this.loadTodos();
    });
  }
}
<h1>To-Do List</h1>

<!-- ฟอร์มเพิ่ม / แก้ไข -->
<div class="form">
  <input [(ngModel)]="title" placeholder="พิมพ์งานที่ต้องทำ..." />
  <button (click)="save()">{{ editingId === null ? 'เพิ่ม' : 'บันทึก' }}</button>
  <button *ngIf="editingId !== null" (click)="cancelEdit()">ยกเลิก</button>
</div>

<!-- รายการ -->
<ul>
  <li *ngFor="let todo of todos">
    <input type="checkbox" [checked]="todo.isCompleted" (change)="toggleCompleted(todo)" />
    <span [class.done]="todo.isCompleted">{{ todo.title }}</span>
    <button (click)="edit(todo)">แก้ไข</button>
    <button (click)="delete(todo.id)">ลบ</button>
  </li>
</ul>

<p *ngIf="todos.length === 0">ยังไม่มีงานในลิสต์</p>
